

public class Operadores_Relacionales { 

			public static void main(String[] args) {
				// TODO Auto-generated method stub
				
				// Igual que ;
				int a = 5;
				int b = 4;
				boolean c = a==b;
				
				System.out.println("a=5 b=4, el resultado de a==b es:" +c);
				System.out.println("");
				
				// Diferente que 
				int d = 4;
				int e = 2;
				boolean f =  d!=e;
				
				System.out.println("d=4 e=2, el resultado de 4 != 2 es: " + f);
				System.out.println("");
				
				// Menor que 
				int g = 5;
				int h = 2;
				boolean i =  g<h;
				
				System.out.println("g=5 h=2, el resultado de 5<2 es: " + i);
				System.out.println("");
				
				// Mayor que 
				int j = 5;
				int k = -5;
				boolean l =  j>k;
				
				System.out.println("j=5 k=-5, el resultado de 5 > -5 es: " + l);
				System.out.println("");
				
				// Menor o igual que 
				int m = 2;
				int n = 3;
				boolean ñ =  m<=n;
				
				System.out.println("m=2 n=3, el resultado de 2 <= 3 es: " + ñ);
				System.out.println("");
				
				// Mayor o igual que 
				int o = 3;
				int p = 9;
				boolean q =  o>=p;
				
				System.out.println("o=3 p=9, el resultado de 3 >= 9 es: " + q);
				System.out.println("");
				
				
			
      }
}
